virtual std::unique_ptr<antlr4::Token> emit() override {
        auto token = Lexer::emit();

        // Create our custom token
        auto newToken = std::make_unique<PositionedToken>(
            token->getType(), 
            token->getText(),
            currentFilename,
            currentLine,
            currentCol,
            atStartOfLine,
            hadLeadingSpace
        );

        // Update position tracking
        currentCol += token->getText().size();
        atStartOfLine = false;
        hadLeadingSpace = false;

        return newToken;
    }

action.new_str:
virtual antlr4::Token* emit() override {
        auto token = Lexer::emit();

        // Create our custom token
        auto newToken = new PositionedToken(
            token->getType(), 
            token->getText(),
            currentFilename,
            currentLine,
            currentCol,
            atStartOfLine,
            hadLeadingSpace
        );

        // Delete the original token
        delete token;

        // Update position tracking
        currentCol += newToken->getText().size();
        atStartOfLine = false;
        hadLeadingSpace = false;

        return newToken;
    }

